const r = $input.first().json.report || {};
const p = r.projects || {};
const pa = r.pending_actions || {};
const f = r.finance || {};
const cc = r.concierge || {};
const byPhase = p.by_phase || {};
const recent = r.recent_projects || [];
const card = (label, value, unit, color) => '<div style="background:'+(color||'#f9fafb')+';padding:14px;border-radius:8px;flex:1;min-width:140px"><div style="font-size:11px;color:#6b7280;text-transform:uppercase;letter-spacing:.5px">'+label+'</div><div style="font-size:26px;font-weight:bold;color:#1f2937;margin-top:6px">'+(value!=null?value:'-')+(unit?'<span style="font-size:14px;color:#6b7280;font-weight:normal"> '+unit+'</span>':'')+'</div></div>';
const row = (cells) => '<tr>'+cells.map(c=>'<td style="padding:8px;border-bottom:1px solid #e5e7eb;font-size:13px">'+c+'</td>').join('')+'</tr>';
const phases = Object.entries(byPhase).map(([k,v])=>'<span style="display:inline-block;background:#e0e7ff;color:#3730a3;padding:3px 10px;border-radius:12px;font-size:12px;margin:2px">'+k+': <b>'+v+'</b></span>').join('') || '<i style="color:#6b7280">sin proyectos activos</i>';
const recentRows = recent.length>0 ? recent.map(p=>row([
  '<b>'+p.name+'</b>',
  p.client_name||'-',
  '<code>'+p.current_phase+'</code>',
  p.budget_target ? Number(p.budget_target).toLocaleString('es-ES')+' EUR' : '-',
  new Date(p.updated_at).toISOString().slice(0,10)
])).join('') : row(['<i>Sin proyectos activos</i>','','','','']);
const urgent = pa.aftercare_urgent || 0;
const overdue = pa.collab_overdue || 0;
const pendingTotal = (pa.consultations||0)+(pa.invoices_pending||0)+(pa.collab_pending_review||0)+(pa.contracts_expiring_7d||0)+overdue+urgent;
const html = '<!DOCTYPE html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>ArquitAI Dashboard</title>' +
'<style>body{font-family:-apple-system,Arial,sans-serif;max-width:1100px;margin:24px auto;padding:16px;color:#1f2937;background:#f3f4f6}h1{color:#0f172a;margin:0 0 8px}h2{color:#374151;font-size:16px;margin:24px 0 8px}.cards{display:flex;gap:12px;flex-wrap:wrap;margin:16px 0}table{width:100%;border-collapse:collapse;background:white;border-radius:8px;overflow:hidden}thead{background:#1f2937;color:white}thead th{padding:10px 8px;text-align:left;font-size:12px}.meta{color:#64748b;font-size:13px}.refresh{display:inline-block;background:#2563eb;color:white;padding:6px 12px;border-radius:4px;text-decoration:none;font-size:13px;margin-left:8px}</style>' +
'</head><body>' +
'<h1>ArquitAI Dashboard <a class="refresh" href="javascript:location.reload()">Refrescar</a></h1>' +
'<div class="meta">Snapshot ' + new Date().toLocaleString('es-ES') + ' — estudio Damian Martinez</div>' +
'<h2>Pulso del estudio</h2>' +
'<div class="cards">' +
  card('Proyectos activos', p.total_active||0) +
  card('Acciones pendientes', pendingTotal, null, pendingTotal>5?'#fef3c7':null) +
  card('Aftercare urgentes', urgent, null, urgent>0?'#fee2e2':null) +
  card('Colab overdue', overdue, null, overdue>0?'#fee2e2':null) +
  card('Cobrado 30d', Number(f.paid_30d_eur||0).toLocaleString('es-ES'), 'EUR') +
  card('Errores 24h', r.errors_24h||0, null, (r.errors_24h||0)>0?'#fee2e2':null) +
'</div>' +
'<h2>Proyectos por fase</h2>' +
'<div style="background:white;padding:14px;border-radius:8px">'+phases+'<div class="meta" style="margin-top:8px">Mas antiguo activo: '+(p.oldest_active_days||0)+' dias — Completados ultimos 30d: '+(p.completed_30d||0)+'</div></div>' +
'<h2>Cola de acciones que requieren al arquitecto</h2>' +
'<div class="cards">' +
  card('Consultas LLM', pa.consultations||0) +
  card('Facturas pendientes', pa.invoices_pending||0) +
  card('Colab review pending', pa.collab_pending_review||0) +
  card('Contratos expiran 7d', pa.contracts_expiring_7d||0) +
  card('QC blocked', pa.qc_blocked||0) +
'</div>' +
'<h2>Concierge cliente (LLM 30d)</h2>' +
'<div class="cards">' +
  card('Preguntas', cc.questions_30d||0) +
  card('Coste', cc.cost_usd_30d||0, 'USD') +
  card('Escalacion', cc.escalation_pct||0, '%') +
'</div>' +
'<h2>Top 10 proyectos activos (recientes)</h2>' +
'<table><thead><tr><th>Proyecto</th><th>Cliente</th><th>Fase</th><th>Budget</th><th>Update</th></tr></thead><tbody>'+recentRows+'</tbody></table>' +
'<p style="color:#94a3b8;font-size:11px;margin-top:32px;text-align:center">JSON crudo: <code>/webhook/dashboard-summary</code> con header X-API-Key. Security dashboard: <code>/webhook/security-dashboard-html</code></p>' +
'</body></html>';
return [{ json: { html: html } }];
